const self = this;
const items = $input.all();
const settings = items[0].json;

const SUPABASE_URL = settings.SUPABASE_URL;
const SUPABASE_API_KEY = settings.SUPABASE_API_KEY;
const RECIPIENT_EMAIL = settings.RECIPIENT_EMAIL;

const now = new Date().toISOString();

// 1. Query published_content where status = 'scheduled'
const scheduled = await self.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/published_content?status=eq.scheduled&select=*`,
  headers: {
    'apikey': SUPABASE_API_KEY,
    'Authorization': `Bearer ${SUPABASE_API_KEY}`,
    'Content-Type': 'application/json'
  }
});

const publishedItems = [];

for (const item of scheduled) {
  // 2. Check if schedule_date is due
  const metadata = typeof item.metadata === 'string' ? JSON.parse(item.metadata) : (item.metadata || {});
  const scheduleDate = metadata.schedule_date;

  if (!scheduleDate) continue;

  // Compare ISO date strings — if schedule_date <= now, it's due
  if (scheduleDate <= now) {
    // 3. Snapshot into content_versions before publishing
    try {
      const vResp = await self.helpers.httpRequest({
        method: 'GET',
        url: `${SUPABASE_URL}/rest/v1/content_versions?content_id=eq.${item.id}&order=version_number.desc&limit=1&select=version_number`,
        headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}`, 'Content-Type': 'application/json' }
      });
      const maxV = Array.isArray(vResp) && vResp.length > 0 ? vResp[0].version_number : 0;
      await self.helpers.httpRequest({
        method: 'POST',
        url: `${SUPABASE_URL}/rest/v1/content_versions`,
        headers: {
          'apikey': SUPABASE_API_KEY,
          'Authorization': `Bearer ${SUPABASE_API_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: {
          content_id: item.id,
          version_number: maxV + 1,
          content_text: item.content_text || '',
          changed_by: 'scheduler',
          change_note: 'Auto-snapshot before scheduled publish'
        },
        json: true
      });
    } catch (e) {
      // Log but don't block publishing
      console.log(`Version snapshot failed for ${item.id}: ${e.message}`);
    }

    // 4. PATCH status to 'published', set published_at, update metadata
    const updatedMetadata = { ...metadata, auto_published: true, auto_published_at: now };
    delete updatedMetadata.schedule_date;

    await self.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/published_content?id=eq.${item.id}`,
      headers: {
        'apikey': SUPABASE_API_KEY,
        'Authorization': `Bearer ${SUPABASE_API_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: {
        status: 'published',
        published_at: now,
        metadata: updatedMetadata
      },
      json: true
    });

    publishedItems.push({
      id: item.id,
      title: item.title || 'Untitled',
      content_type: item.content_type || 'unknown',
      schedule_date: scheduleDate
    });
  }
}

// 5. Build summary
const publishedCount = publishedItems.length;
const sendNotification = publishedCount > 0;

let notificationBody = '';
let notificationSubject = '';
let result = '';

if (sendNotification) {
  const listItems = publishedItems.map(p =>
    `<li><strong>${p.title}</strong> (${p.content_type}) \u2014 scheduled for ${p.schedule_date}</li>`
  ).join('\n  ');

  notificationBody = `<h2>Scheduled Content Published</h2>
<p>${publishedCount} item(s) automatically published:</p>
<ul>
  ${listItems}
</ul>`;

  notificationSubject = `Auto-Published: ${publishedCount} scheduled item(s)`;
  result = `Published ${publishedCount} scheduled item(s): ${publishedItems.map(p => p.title).join(', ')}`;
} else {
  result = 'No scheduled content due for publishing.';
  notificationSubject = '';
  notificationBody = '';
}

return [{
  json: {
    result,
    published_count: publishedCount,
    send_notification: sendNotification,
    notification_subject: notificationSubject,
    notification_body: notificationBody,
    recipient_email: RECIPIENT_EMAIL
  }
}];
